{
  "intent": "check_and_fix",
  "intent_description": "DHCP on router2 is handing out wrong default gateway (192.168.0.1) to hosts in 172.16.0.0/24, causing 172.16.0.12 to be unreachable. Restore correct gateway and force host to get corrected lease so 172.16.0.12 becomes reachable.",
  "target": "172.16.0.12",
  "needs_fix": true,
  "plan": {
    "problem": "R2 DHCP pool 'R2_LAN' default-router is 192.168.0.1; LAN gateway should be 172.16.0.1. DHCP clients (including 172.16.0.12) are using wrong gateway and are unreachable.",
    "fix_summary": "Update DHCP pool 'R2_LAN' default-router to 172.16.0.1 on router2; clear DHCP binding for 172.16.0.12 to force lease renewal.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "update_dhcp_pool",
        "target": "R2_LAN",
        "parameters": [
          "default-router=172.16.0.1"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "clear_dhcp_binding",
        "target": "172.16.0.12",
        "parameters": [
          "pool=R2_LAN"
        ]
      }
    ]
  }
}
